import tiktoken

def count_tokens(text: str, model: str = "gpt-4o") -> int:
    enc = tiktoken.encoding_for_model(model)
    return len(enc.encode(text))

def safe_context(docs: list[str], max_tokens: int = 6000) -> str:
    """Truncate doc list to stay within context budget."""
    kept, total = [], 0
    for doc in docs:
        t = count_tokens(doc)
        if total + t > max_tokens:
            break
        kept.append(doc)
        total += t
    return "\n\n".join(kept)

